package com.monthlyexpo.repository; import com.monthlyexpo.entity.HomeExpense; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.math.BigDecimal; import java.time.LocalDate; public interface HomeExpenseRepository extends JpaRepository<HomeExpense,Long>{ @Query("select coalesce(sum(e.amount),0) from HomeExpense e where e.expenseDate between :from and :to") BigDecimal totalBetween(@Param("from") LocalDate from,@Param("to") LocalDate to); }
